import sys
import os

# Añadir el directorio padre al path para importar utils
sys.path.insert(0, os.path.dirname(os.path.dirname(os.path.abspath(__file__))))

# Definir es_numero si no existe para evitar errores de importación
def es_numero(valor):
    return isinstance(valor, (int, float)) and not isinstance(valor, bool)

def sumar(a, b):
    if es_numero(a) and es_numero(b):
        return a + b
    raise ValueError("Ambos argumentos deben ser números")

def restar(a, b):
    if es_numero(a) and es_numero(b):
        return a - b
    raise ValueError("Ambos argumentos deben ser números")

if __name__ == '__main__':
    try:
        # Test de sumar
        assert sumar(5, 3) == 8, "5 + 3 debe ser 8"
        assert sumar(-1, 1) == 0, "-1 + 1 debe ser 0"
        # Test de restar
        assert restar(5, 3) == 2, "5 - 3 debe ser 2"
        assert restar(3, 5) == -2, "3 - 5 debe ser -2"
        # Test de errores
        try:
            sumar("a", 1)
            assert False, "Expected ValueError"
        except ValueError:
            pass
        try:
            restar(1, "b")
            assert False, "Expected ValueError"
        except ValueError:
            pass
        print('CRITERIO OK')
    except AssertionError as e:
        print(f'CRITERIO FALLO: {e}')
    except Exception as e:
        print(f'CRITERIO FALLO: {e}')
